	(8003, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'Я был на нескольких музыкальных фестивалях по всему миру.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8004, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'Бразильская музыка, такая как босса-нова и самба, невероятна!', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8005, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'Моя дочь берет уроки вокала и очень прогрессирует.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8006, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'Я всегда создаю разные плейлисты для каждого времени года.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8007, 47, '音楽のない人生は想像できません。', 'Я не могу представить свою жизнь без музыки.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8008, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'Давайте споем караоке завтра вечером? Я уже знаю несколько песен.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8009, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'Музыка — это форма искусства, которая объединяет людей по всему миру.', 8, 9, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 616, 1, 1, NULL),
	(8010, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', 'أحب الاستماع إلى الموسيقى الكلاسيكية للاسترخاء بعد العمل.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8011, 47, '何か楽器を演奏しますか？私はギターを弾きます。', 'هل تعزف على أي آلة موسيقية؟ أنا أعزف على الجيتار.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8012, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', 'ما هي فرقتك المفضلة؟ أنا أحب البيتلز.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8013, 47, '来月ロックコンサートに行きます。とても楽しみです！', 'سأذهب إلى حفل موسيقى الروك الشهر القادم. أنا متحمس جدًا!', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8014, 47, '音楽は勉強中に集中するのに役立ちます。', 'الموسيقى تساعدني على التركيز عندما أدرس.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8015, 47, '私は子供の頃にピアノを弾くことを学びました。', 'تعلمت العزف على البيانو عندما كنت طفلًا.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8016, 47, '運転中にどんな音楽を聴くのが好きですか？', 'أي نوع من الموسيقى تحب الاستماع إليه عندما تقود السيارة؟', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8017, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', 'أفضل الموسيقى الآلية بدون غناء للعمل.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8018, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'لقد ذهبت إلى عدة مهرجانات موسيقية حول العالم.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8019, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'الموسيقى البرازيلية، مثل البوسا نوفا والسامبا، رائعة!', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8020, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'ابنتي تأخذ دروسًا في الغناء وتتحسن كثيرًا.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8021, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'أقوم دائمًا بإنشاء قوائم تشغيل مختلفة لكل فصل من السنة.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8022, 47, '音楽のない人生は想像できません。', 'لا أستطيع تخيل حياتي بدون موسيقى.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8023, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'هل نغني الكاريوكي غدًا في المساء؟ أنا أعرف بالفعل بعض الأغاني.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8024, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'الموسيقى هي شكل من أشكال الفن يربط الناس حول العالم.', 8, 10, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 617, 1, 1, NULL),
	(8025, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', 'मुझे काम के बाद आराम करने के लिए शास्त्रीय संगीत सुनना पसंद है।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8026, 47, '何か楽器を演奏しますか？私はギターを弾きます。', 'क्या आप कोई संगीत वाद्ययंत्र बजाते हैं? मैं गिटार बजाता हूँ।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8027, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', 'आपका पसंदीदा बैंड कौन सा है? मुझे बीटल्स पसंद हैं।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8028, 47, '来月ロックコンサートに行きます。とても楽しみです！', 'मैं अगले महीने एक रॉक कॉन्सर्ट में जा रहा हूँ। मैं बहुत उत्साहित हूँ!', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8029, 47, '音楽は勉強中に集中するのに役立ちます。', 'पढ़ाई करते समय संगीत मुझे ध्यान केंद्रित करने में मदद करता है।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8030, 47, '私は子供の頃にピアノを弾くことを学びました。', 'मैंने बचपन में पियानो बजाना सीखा था।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8031, 47, '運転中にどんな音楽を聴くのが好きですか？', 'गाड़ी चलाते समय आप किस तरह का संगीत सुनना पसंद करते हैं?', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8032, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', 'मैं काम के लिए बिना गायन के वाद्य संगीत पसंद करता हूँ।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8033, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'मैं दुनिया भर में कई संगीत समारोहों में गया हूँ।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8034, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'ब्राज़ीलियाई संगीत, जैसे बोसा नोवा और सांबा, अद्भुत है!', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8035, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'मेरी बेटी गायन की कक्षाएं ले रही है और बहुत सुधार कर रही है।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8036, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'मैं हमेशा हर मौसम के लिए अलग-अलग प्लेलिस्ट बनाता हूँ।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8037, 47, '音楽のない人生は想像できません。', 'मैं संगीत के बिना अपने जीवन की कल्पना नहीं कर सकता।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8038, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'कल रात कराओके गाते हैं? मुझे कुछ गाने पहले से आते हैं।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8039, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'संगीत एक कला रूप है जो दुनिया भर के लोगों को जोड़ता है।', 8, 11, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 618, 1, 1, NULL),
	(8040, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', '나는 일 후에 휴식을 위해 클래식 음악을 듣는 것을 좋아합니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8041, 47, '何か楽器を演奏しますか？私はギターを弾きます。', '어떤 악기를 연주하시나요? 저는 기타를 칩니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8042, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', '좋아하는 밴드는 무엇인가요? 저는 비틀즈를 좋아합니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8043, 47, '来月ロックコンサートに行きます。とても楽しみです！', '다음 달에 록 콘서트에 갈 예정입니다. 정말 신나요!', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8044, 47, '音楽は勉強中に集中するのに役立ちます。', '음악은 공부할 때 집중하는 데 도움이 됩니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8045, 47, '私は子供の頃にピアノを弾くことを学びました。', '저는 어렸을 때 피아노를 배웠습니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8046, 47, '運転中にどんな音楽を聴くのが好きですか？', '운전할 때 어떤 음악을 듣는 것을 좋아하나요?', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8047, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', '나는 일할 때 보컬이 없는 기악 음악을 선호합니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8048, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', '나는 전 세계 여러 음악 축제에 가본 적이 있습니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8049, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', '보사노바와 삼바 같은 브라질 음악은 정말 놀랍습니다!', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8050, 47, '娘は歌のレッスンを受けていて、とても上達しています。', '제 딸이 노래 레슨을 받고 있고 많이 실력이 향상되고 있습니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8051, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', '나는 항상 계절마다 다른 플레이리스트를 만듭니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8052, 47, '音楽のない人生は想像できません。', '나는 음악 없는 내 삶을 상상할 수 없어요.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8053, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', '내일 밤에 노래방 갈래요? 저는 벌써 몇 곡 알고 있어요.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8054, 47, '音楽は世界中の人々をつなぐ芸術形式です。', '음악은 전 세계 사람들을 연결하는 예술 형식입니다.', 8, 12, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 619, 1, 1, NULL),
	(8055, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', 'Ik luister graag naar klassieke muziek om te ontspannen na het werk.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8056, 47, '何か楽器を演奏しますか？私はギターを弾きます。', 'Speel je een muziekinstrument? Ik speel gitaar.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8057, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', 'Wat is je favoriete band? Ik hou van de Beatles.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8058, 47, '来月ロックコンサートに行きます。とても楽しみです！', 'Ik ga volgende maand naar een rockconcert. Ik ben zo opgewonden!', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8059, 47, '音楽は勉強中に集中するのに役立ちます。', 'Muziek helpt me concentreren als ik aan het studeren ben.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8060, 47, '私は子供の頃にピアノを弾くことを学びました。', 'Ik leerde piano spelen toen ik een kind was.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8061, 47, '運転中にどんな音楽を聴くのが好きですか？', 'Wat voor muziek luister je graag als je aan het rijden bent?', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8062, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', 'Ik geef de voorkeur aan instrumentale muziek, zonder zang, voor het werk.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8063, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'Ik ben naar verschillende muziekfestivals over de hele wereld geweest.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8064, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'Braziliaanse muziek, zoals bossa nova en samba, is geweldig!', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8065, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'Mijn dochter neemt zanglessen en gaat hard vooruit.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8066, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'Ik maak altijd verschillende afspeellijsten voor elk seizoen.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8067, 47, '音楽のない人生は想像できません。', 'Ik kan me mijn leven niet voorstellen zonder muziek.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8068, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'Zullen we morgenavond karaoke zingen? Ik ken al een paar nummers.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8069, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'Muziek is een kunstvorm die mensen over de hele wereld verbindt.', 8, 13, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 620, 1, 1, NULL),
	(8070, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', 'İşten sonra rahatlamak için klasik müzik dinlemeyi seviyorum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8071, 47, '何か楽器を演奏しますか？私はギターを弾きます。', 'Herhangi bir müzik aleti çalıyor musun? Ben gitar çalıyorum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8072, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', 'En sevdiğin grup hangisi? Beatles\'ı çok seviyorum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8073, 47, '来月ロックコンサートに行きます。とても楽しみです！', 'Gelecek ay bir rock konserine gidiyorum. Çok heyecanlıyım!', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8074, 47, '音楽は勉強中に集中するのに役立ちます。', 'Ders çalışırken müzik odaklanmama yardımcı oluyor.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8075, 47, '私は子供の頃にピアノを弾くことを学びました。', 'Çocukken piyano çalmayı öğrendim.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8076, 47, '運転中にどんな音楽を聴くのが好きですか？', 'Araba kullanırken ne tür müzik dinlemeyi seversin?', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8077, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', 'Çalışmak için vokalsiz enstrümantal müziği tercih ederim.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8078, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'Dünyanın dört bir yanındaki birçok müzik festivaline gittim.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8079, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'Bossa nova ve samba gibi Brezilya müziği inanılmaz!', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8080, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'Kızım şan dersleri alıyor ve çok gelişiyor.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8081, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'Her mevsim için her zaman farklı çalma listeleri oluştururum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8082, 47, '音楽のない人生は想像できません。', 'Hayatımı müzik olmadan hayal edemiyorum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8083, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'Yarın akşam karaoke söyleyelim mi? Zaten birkaç şarkı biliyorum.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8084, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'Müzik, dünya çapındaki insanları birbirine bağlayan bir sanat formudur.', 8, 14, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 621, 1, 1, NULL),
	(8085, 47, '仕事の後はクラシック音楽を聴いてリラックスするのが大好きです。', 'Uwielbiam słuchać muzyki klasycznej, aby zrelaksować się po pracy.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8086, 47, '何か楽器を演奏しますか？私はギターを弾きます。', 'Grasz na jakimś instrumencie muzycznym? Gram na gitarze.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8087, 47, '好きなバンドは何ですか？私はビートルズが大好きです。', 'Jaki jest twój ulubiony zespół? Uwielbiam Beatlesów.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8088, 47, '来月ロックコンサートに行きます。とても楽しみです！', 'Idę na koncert rockowy w przyszłym miesiącu. Jestem bardzo podekscytowany!', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8089, 47, '音楽は勉強中に集中するのに役立ちます。', 'Muzyka pomaga mi się skoncentrować, gdy się uczę.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8090, 47, '私は子供の頃にピアノを弾くことを学びました。', 'Nauczyłem się grać na pianinie, gdy byłem dzieckiem.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8091, 47, '運転中にどんな音楽を聴くのが好きですか？', 'Jakiego rodzaju muzyki słuchasz, gdy prowadzisz?', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8092, 47, '仕事中はボーカルのないインストゥルメンタル音楽が好きです。', 'Do pracy wolę muzykę instrumentalną, bez wokalu.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8093, 47, '私は世界中のいくつかの音楽フェスティバルに行ったことがあります。', 'Byłem na kilku festiwalach muzycznych na całym świecie.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8094, 47, 'ボサノバやサンバのようなブラジル音楽は素晴らしいです！', 'Muzyka brazylijska, taka jak bossa nova i samba, jest niesamowita!', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8095, 47, '娘は歌のレッスンを受けていて、とても上達しています。', 'Moja córka bierze lekcje śpiewu i robi duże postępy.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8096, 47, '私はいつも季節ごとに異なるプレイリストを作ります。', 'Zawsze tworzę różne playlisty na każdą porę roku.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8097, 47, '音楽のない人生は想像できません。', 'Nie wyobrażam sobie życia bez muzyki.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8098, 47, '明日の夜カラオケに行きませんか？もう何曲か知っています。', 'Zaśpiewajmy karaoke jutro wieczorem? Znam już kilka piosenek.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
	(8099, 47, '音楽は世界中の人々をつなぐ芸術形式です。', 'Muzyka jest formą sztuki, która łączy ludzi na całym świecie.', 8, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 622, 1, 1, NULL),
