	(8298, 47, 'Я иду на рок-концерт в следующем месяце. Я так взволнован!', 'Idę na koncert rockowy w przyszłym miesiącu. Jestem bardzo podekscytowany!', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
	(8299, 47, 'Музыка помогает мне сосредоточиться, когда я занимаюсь.', 'Muzyka pomaga mi się skoncentrować, gdy się uczę.', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
	(8300, 47, 'Я научился играть на пианино в детстве.', 'Nauczyłem się grać na pianinie, gdy byłem dzieckiem.', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
	(8301, 47, 'Какую музыку ты любишь слушать, когда водишь машину?', 'Jakiego rodzaju muzyki słuchasz, gdy prowadzisz?', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
	(8302, 47, 'Для работы я предпочитаю инструментальную музыку без вокала.', 'Do pracy wolę muzykę instrumentalną, bez wokalu.', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
	(8303, 47, 'Я был на нескольких музыкальных фестивалях по всему миру.', 'Byłem na kilku festiwalach muzycznych na całym świecie.', 9, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 636, 1, 1, NULL),
