	(8514, 47, 'الموسيقى البرازيلية، مثل البوسا نوفا والسامبا، رائعة!', 'Muzyka brazylijska, taka jak bossa nova i samba, jest niesamowita!', 10, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 650, 1, 1, NULL),
	(8515, 47, 'ابنتي تأخذ دروسًا في الغناء وتتحسن كثيرًا.', 'Moja córka bierze lekcje śpiewu i robi duże postępy.', 10, 15, '2026-07-21 15:01:10', '2026-07-21 15:01:10', 650, 1, 1, NULL),
